pragma solidity ^0.8.0;

import "@chainlink/contracts/src/v0.8/interfaces/AggregatorV3Interface.sol";

contract PriceConsumerV3 {
 AggregatorV3Interface internal priceFeed;

 constructor(address _priceFeedAddress) {
 priceFeed = AggregatorV3Interface(_priceFeedAddress);
 }

 function getLatestPrice() public view returns (int) {
 (
 uint80 roundID,
 int price,
 uint startedAt,
 uint timeStamp,
 uint80 answeredInRound
 ) = priceFeed.latestRoundData();

 require(price > 0, "Invalid price data");
 return price;
 }

 function getDecimals() public view returns (uint8) {
 return priceFeed.decimals();
 }
}

async function requestOracleData(oracleNodeAddress, jobId, url) {
 // Step 1: Define the data request parameters
 const requestParams = {
 oracle: oracleNodeAddress,
 jobId: jobId,
 url: url,
 path: 'price', // JSON path to extract data
 times: 100 // Multiplier for decimal precision
 };

 // Step 2: Submit request to oracle network
 const requestTx = await oracleContract.requestEthereumPrice(
 requestParams.oracle,
 requestParams.jobId,
 requestParams.url,
 requestParams.path,
 requestParams.times
 );

 // Step 3: Listen for oracle callback with data
 oracleContract.on("ChainlinkRequested", (requestId) => {
 console.log("Oracle request sent, ID:", requestId);
 });

 oracleContract.on("ChainlinkFulfilled", (requestId, data) => {
 console.log("Data received:", data.toString());
 // Data is now available for smart contract use
 });

 return requestTx;
}
